use std::net::SocketAddr;
use tokio::sync::{mpsc, oneshot};
use std::collections::HashMap;

struct NodeState {
    peers: HashMap<SocketAddr, bool>,
    log_index: u64,
}
impl Default for NodeState {
    fn default() -> Self {
        NodeState {
            peers: HashMap::new(),
            log_index: 0,
        }
    }
}

async fn handle_incoming_message(addr: SocketAddr, mut rx: mpsc::Receiver<String>) -> Result<(), Box<dyn std::error::Error + Send>> {
    let mut state = NodeState::default();
    println!("Node {} started listening for messages.", addr);

    while let Some(message) = rx.recv().await {
        println!("Received message from {}: {}", addr, message); 
        if message.contains("COMMIT") {
            state.log_index += 1;
            println!("State updated: New log index is {}", state.log_index);
        } else {
            println!("Unknown command received.");
        }
    }
    Ok(()) 
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error + Send>> {
    let (tx, rx) = mpsc::channel::<String>(32);
    let node_addr: SocketAddr = "127.0.0.1:8080".parse().unwrap();

    let handler_task = tokio::spawn(handle_incoming_message(node_addr, rx));

    tokio::time::sleep(std::time::Duration::from_millis(100)).await;
    println!("Main thread sending initial message...");
    tx.send("INIT: Start consensus round".to_string()).await.ok();

    tokio::time::sleep(std::time::Duration::from_millis(500)).await;
    println!("Main thread sending commit signal...");
    tx.send("COMMIT: Finalize block 42".to_string()).await.ok();

    tokio::time::sleep(std::time::Duration::from_millis(300)).await;
    println!("Main thread shutting down.");

    handler_task.await.ok();
    Ok(())
}

use std::net::TcpStream;
use std::io::{self, Write};

struct SimulationData {
    generation: u64,
    grid_state: Vec<u8>,
}

fn simulate_and_send(socket: &mut TcpStream, data: SimulationData) -> io::Result<()> {
    let mut buffer = String::new();
    buffer.push_str(&format!("GENERATION:{}n", data.generation));
    for byte in data.grid_state.iter() {
        buffer.push_str(&format!("{}", *byte as u64));
        buffer.push_str(":");
    }
    buffer.push_str(&format!("nSIZE:{}n", data.grid_state.len()));

    socket.write_all(buffer.as_bytes())?;
    Ok(())
}

fn main() -> io::Result<()> {
    let mut stream = TcpStream::connect("127.0.0.1:8080")
        .expect("Failed to connect to server.");

    let initial_data = SimulationData {
        generation: 1,
        grid_state: vec![1, 0, 1, 1, 0],
    };

    match simulate_and_send(&mut stream, initial_data) {
        Ok(_) => println!("Successfully simulated and sent data over TCP."),
        Err(e) => eprintln!("Error sending simulation data: {}", e),
    }

    Ok(())
}

use std::io::{self, Write};

struct PacketData {
    source_ip: String,
    destination_port: u16,
    payload_length: usize,
}

fn process_packet(data: PacketData) -> io::Result<()> {
    let mut buffer = Vec::new();
    buffer.extend_from_slice(format!("Received packet from {} on port {}. Length: {}", data.source_ip, data.destination_port, data.payload_length).as_bytes());
    print!("Processing: {} r", String::from_utf8_lossy(&buffer));
    io::stdout().flush()?;
    Ok(())
}

fn handle_incoming_stream(packet_sources: Vec<PacketData>) -> io::Result<()> {
    println!("Starting stream processing...");
    let mut processed_count = 0;
    for packet in packet_sources {
        match process_packet(packet) {
            Ok(_) => {
                processed_count += 1;
            }
            Err(e) => {
                eprintln!("Error processing packet: {}", e);
            }
        }
    }
    println!("nFinished stream. Successfully processed {} items.", processed_count);
    Ok(())
}

fn main() -> io::Result<()> {
    let sources = vec![ 
        PacketData { source_ip: "192.168.1.1".to_string(), destination_port: 8080, payload_length: 15 },
        PacketData { source_ip: "10.0.0.5".to_string(), destination_port: 443, payload_length: 22 },
        PacketData { source_ip: "203.0.113.99".to_string(), destination_port: 80, payload_length: 7 },
    ];
    handle_incoming_stream(sources)
}

use std::collections::HashMap;

struct ConnectionLayerAnalyzer {
    compatibility_matrix: HashMap<String, HashMap<String, bool>>,
}

impl ConnectionLayerAnalyzer {
    fn new() -> Self {
        let mut matrix = HashMap::new();
        let mut http2_map = HashMap::new();
        http2_map.insert("http/3".to_string(), true);
        http2_map.insert("tcp".to_string(), true);
        matrix.insert("http/2".to_string(), http2_map);

        let mut http3_map = HashMap::new();
        http3_map.insert("http/2".to_string(), true);
        http3_map.insert("quic".to_string(), true);
        matrix.insert("http/3".to_string(), http3_map);

        Self { compatibility_matrix: matrix }
    }

    fn check_compatibility(&self, layer_a: &str, layer_b: &str) -> Option<bool> {
        if let Some(inner_map) = self.compatibility_matrix.get(layer_a) {
            return inner_map.get(layer_b).copied();
        }
        None
    }
}

fn main() {
    let analyzer = ConnectionLayerAnalyzer::new();
    let compatible1 = analyzer.check_compatibility("http/2", "http/3");
    println!("Is http/2 compatible with http/3? {}", compatible1.unwrap_or(false));

    let compatible2 = analyzer.check_compatibility("http/3", "quic");
    println!("Is http/3 compatible with quic? {}", compatible2.unwrap_or(false));

    let incompatible = analyzer.check_compatibility("unknown", "http/2");
    println!("Is unknown compatible with http/2? {}", incompatible.unwrap_or(false));
}
